namespace sv_bc6889ff9dc64438930fb696d3df5a85.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_bc6889ff9dc64438930fb696d3df5a85.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

@if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="RetryAsync">Retry</button>
    </div>
}
else
{
    <div class="row">
        @* ── Left Sidebar (Filters) ── *@
        <div class="col-lg-3">
            <div class="card mb-4">
                <div class="card-header fw-semibold">Filters</div>
                <div class="card-body">
                    @* Category checkboxes *@
                    <h6>Category</h6>
                    @if (_categories is null)
                    {
                        <p class="text-muted small">Loading categories…</p>
                    }
                    else
                    {
                        @foreach (var cat in _categories)
                        {
                            <div class="form-check">
                                <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                       checked="@_selectedCategories.Contains(cat)"
                                       @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                                <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                            </div>
                        }
                    }

                    <hr />

                    @* Price range *@
                    <h6>Price Range</h6>
                    <div class="mb-2">
                        <label class="form-label small mb-0">Min Price</label>
                        <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                               @bind="_minPrice" placeholder="0.00" />
                    </div>
                    <div class="mb-2">
                        <label class="form-label small mb-0">Max Price</label>
                        <input type="number" class="form-control form-control-sm" min="0" step="0.01"
                               @bind="_maxPrice" placeholder="Any" />
                    </div>

                    <hr />

                    @* In Stock toggle *@
                    <div class="form-check mb-3">
                        <input class="form-check-input" type="checkbox" id="inStockOnly"
                               @bind="_inStockOnly" />
                        <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                    </div>

                    @* Action buttons *@
                    <div class="d-grid gap-2">
                        <button class="btn btn-primary btn-sm" @onclick="ApplyFiltersAsync" disabled="@_loading">
                            Apply Filters
                        </button>
                        <button class="btn btn-outline-secondary btn-sm" @onclick="ClearFiltersAsync" disabled="@_loading">
                            Clear Filters
                        </button>
                    </div>
                </div>
            </div>
        </div>

        @* ── Main Content Area ── *@
        <div class="col-lg-9">
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3 flex-wrap gap-2">
                <div class="d-flex align-items-center gap-2">
                    <label class="form-label mb-0 fw-semibold" for="sortBy">Sort:</label>
                    <select id="sortBy" class="form-select form-select-sm" style="width:auto"
                            @bind="_sortBy" @bind:after="SortChangedAsync">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A-Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted small">
                    @if (_result is not null && _result.Items.Count > 0)
                    {
                        var start = (_result.Page - 1) * _result.PageSize + 1;
                        var end = start + _result.Items.Count - 1;
                        <text>Showing @start–@end of @_result.TotalCount products</text>
                    }
                </span>
            </div>

            @* Loading state *@
            @if (_loading)
            {
                <div class="text-center py-5">
                    <div class="spinner-border text-primary" role="status">
                        <span class="visually-hidden">Loading…</span>
                    </div>
                    <p class="mt-2 text-muted">Loading products…</p>
                </div>
            }
            @* Empty state *@
            else if (_result is not null && _result.Items.Count == 0)
            {
                <div class="text-center py-5">
                    <h4 class="text-muted">No products found</h4>
                    <p class="text-muted">Try adjusting your filters.</p>
                </div>
            }
            @* Product grid *@
            else if (_result is not null)
            {
                <div class="row row-cols-1 row-cols-md-2 row-cols-xl-3 g-4">
                    @foreach (var product in _result.Items)
                    {
                        <div class="col">
                            <ProductCard Product="product"
                                         OnProductClicked="HandleProductClicked"
                                         OnAddToCart="HandleAddToCart" />
                        </div>
                    }
                </div>

                @* Pagination *@
                @if (TotalPages > 1)
                {
                    <nav class="mt-4" aria-label="Product pagination">
                        <ul class="pagination justify-content-center flex-wrap">
                            <li class="page-item @(_currentPage == 1 ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage - 1)"
                                        disabled="@(_currentPage == 1)">
                                    Previous
                                </button>
                            </li>
                            @for (var i = 1; i <= TotalPages; i++)
                            {
                                var page = i;
                                <li class="page-item @(page == _currentPage ? "active" : "")">
                                    <button class="page-link" @onclick="() => GoToPageAsync(page)">@page</button>
                                </li>
                            }
                            <li class="page-item @(_currentPage == TotalPages ? "disabled" : "")">
                                <button class="page-link" @onclick="() => GoToPageAsync(_currentPage + 1)"
                                        disabled="@(_currentPage == TotalPages)">
                                    Next
                                </button>
                            </li>
                        </ul>
                    </nav>
                }
            }
        </div>
    </div>
}

@code {
    [Parameter] public EventCallback<Product> OnProductSelected { get; set; }

    private List<string>? _categories;
    private PagedResult<Product>? _result;

    private HashSet<string> _selectedCategories = new();
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private const int PageSize = 9;

    private bool _loading = true;
    private string? _error;

    private int TotalPages => _result is null or { TotalCount: 0 }
        ? 1
        : (int)Math.Ceiling((double)_result.TotalCount / _result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            _loading = true;
            _error = null;

            var categoriesTask = _categories is null
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(_categories);

            var searchTask = ProductService.SearchAsync(BuildFilter(), _sortBy, _currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            _categories = await categoriesTask;
            _result = await searchTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private ProductFilter BuildFilter() => new(
        Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
        MinPrice: _minPrice,
        MaxPrice: _maxPrice,
        InStockOnly: _inStockOnly
    );

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFiltersAsync()
    {
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task ClearFiltersAsync()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task SortChangedAsync()
    {
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task GoToPageAsync(int page)
    {
        if (page < 1 || page > TotalPages) return;
        _currentPage = page;
        await LoadDataAsync();
    }

    private async Task RetryAsync()
    {
        await LoadDataAsync();
    }

    private async Task HandleProductClicked(Product product)
    {
        if (OnProductSelected.HasDelegate)
            await OnProductSelected.InvokeAsync(product);
    }

    private void HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart logic
    }
}

@using sv_bc6889ff9dc64438930fb696d3df5a85.Services

<div class="card h-100 product-card" @onclick="OnCardClicked" role="button">
    <div class="product-image-placeholder d-flex align-items-center justify-content-center bg-light"
         style="height:180px;">
        <span class="text-muted small text-center px-2">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <div class="mb-2" title="@($"{Product.Rating:F1} out of 5")">
            @RenderStars(Product.Rating)
        </div>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="AddToCartClicked"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public Product Product { get; set; } = default!;
    [Parameter] public EventCallback<Product> OnProductClicked { get; set; }
    [Parameter] public EventCallback<Product> OnAddToCart { get; set; }

    private static string RenderStars(double rating)
    {
        var fullStars = (int)Math.Round(rating);
        var empty = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', empty);
    }

    private async Task OnCardClicked()
    {
        if (OnProductClicked.HasDelegate)
            await OnProductClicked.InvokeAsync(Product);
    }

    private async Task AddToCartClicked()
    {
        if (OnAddToCart.HasDelegate)
            await OnAddToCart.InvokeAsync(Product);
    }
}

::deep .product-card {
    cursor: pointer;
    transition: box-shadow 0.2s, transform 0.15s;
}

::deep .product-card:hover {
    box-shadow: 0 4px 16px rgba(0, 0, 0, 0.12);
    transform: translateY(-2px);
}

::deep .product-image-placeholder {
    border-bottom: 1px solid #dee2e6;
    font-size: 0.9rem;
}

