toolArgs.file_text:
@using sv_bc6889ff9dc64438930fb696d3df5a85.Services

<div class="card h-100 product-card" @onclick="OnCardClicked" role="button">
    <div class="product-image-placeholder d-flex align-items-center justify-content-center bg-light"
         style="height:180px;">
        <span class="text-muted small text-center px-2">@Product.Name</span>
    </div>
    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <div class="mb-2" title="@($"{Product.Rating:F1} out of 5")">
            @RenderStars(Product.Rating)
        </div>
        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }
        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="AddToCartClicked"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public Product Product { get; set; } = default!;
    [Parameter] public EventCallback<Product> OnProductClicked { get; set; }
    [Parameter] public EventCallback<Product> OnAddToCart { get; set; }

    private static string RenderStars(double rating)
    {
        var fullStars = (int)Math.Round(rating);
        var empty = 5 - fullStars;
        return new string('★', fullStars) + new string('☆', empty);
    }

    private async Task OnCardClicked()
    {
        if (OnProductClicked.HasDelegate)
            await OnProductClicked.InvokeAsync(Product);
    }

    private async Task AddToCartClicked()
    {
        if (OnAddToCart.HasDelegate)
            await OnAddToCart.InvokeAsync(Product);
    }
}

